const API_BASE = 'https://api.octacode.pt';
const COMPANY = 'RAMONCARLOS';
const DOC_TYPE = 'geraldocs';
const CLIENT_ID = '336';
const EMAIL = 'ramonp.rios@gmail.com';
const PASSWORD = 'CHANGE_ME_IN_N8N';

const items = $input.all();
const results = [];
let accessToken = '';

try {
  const loginResp = await fetch(API_BASE + '/login', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json' },
    body: JSON.stringify({ identifier: EMAIL, password: PASSWORD })
  });
  const loginData = await loginResp.json();
  accessToken = loginData.access_token || '';
  if (!accessToken) throw new Error('No access_token in login response');
} catch (err) {
  return items.map(i => ({ json: { fileName: i.json.fileName || '', folderId: i.json.folderId || '', octaStatus: 'auth_failed', octaError: err.message } }));
}

for (const item of items) {
  const fileName = item.json.fileName || 'unknown.pdf';
  const folderId = item.json.folderId || '';
  const binaryData = item.binary?.data;

  if (!binaryData) {
    results.push({ json: { fileName, folderId, octaStatus: 'skipped', octaError: 'no binary data' } });
    continue;
  }

  try {
    const params = new URLSearchParams({ client_id: CLIENT_ID, license_code: '', company_name: COMPANY, document_type: DOC_TYPE, document_name: fileName });
    const presignResp = await fetch(API_BASE + '/documentstorage/upload?' + params, { headers: { 'Authorization': 'Bearer ' + accessToken, 'Accept': 'application/json' } });
    const presignData = await presignResp.json();
    const presignedUrl = presignData.attributes;
    if (!presignedUrl) throw new Error('No presigned URL returned');
    const pdfBuffer = Buffer.from(binaryData.data, binaryData.encoding || 'base64');
    const blob = new Blob([pdfBuffer], { type: 'application/pdf' });
    const uploadResp = await fetch(presignedUrl, { method: 'PUT', body: blob, headers: { 'Content-Type': 'application/pdf' } });
    results.push({ json: { fileName, folderId, octaStatus: uploadResp.ok ? 'uploaded' : 'failed', octaCode: uploadResp.status } });
  } catch (err) {
    results.push({ json: { fileName, folderId, octaStatus: 'error', octaError: err.message } });
  }
}

return results;
